"use strict";(self.webpackChunksfit_delivery_knowledge_hub=self.webpackChunksfit_delivery_knowledge_hub||[]).push([[4691],{1157:e=>{e.exports=JSON.parse('{"label":"Delivery","permalink":"/docs/tags/delivery","allTagsPath":"/docs/tags","count":3,"items":[{"id":"Practices_and_Processes/02_04_Delivery_Strategies/02_04_01_Fundamentals_of_Delivery_Strategies","title":"Fundamentals of Delivery Strategies","description":"In modern change management, the key task is to minimize risks when deploying new features while ensuring system stability. Deployment methods such as Big Bang, Phased Rollouts, Dark Launches, Blue-Green Deployment, and A/B Testing allow for a flexible approach to implementing changes depending on the context and business goals.","permalink":"/docs/Practices_and_Processes/02_04_Delivery_Strategies/02_04_01_Fundamentals_of_Delivery_Strategies"},{"id":"Practices_and_Processes/02_01_Release/02_01_05_Large-scale_Projects","title":"Large-scale Projects","description":"Release management in large projects, which involve multiple teams and/or organizations, is a significant challenge. The success of implementing changes, system stability, and user satisfaction depends on proper coordination and management. Release management in such projects must include distinctive strategies and approaches to minimize risks and ensure the alignment of all participants\' actions.","permalink":"/docs/Practices_and_Processes/02_01_Release/02_01_05_Large-scale_Projects"},{"id":"Practices_and_Processes/02_01_Release/02_01_03_Release_on_Demand","title":"Release on Demand","description":"What is Release on Demand?","permalink":"/docs/Practices_and_Processes/02_01_Release/02_01_03_Release_on_Demand"}],"unlisted":false}')}}]);